#include "controller.h"

#include <string.h>

static void controller_set_safe_idle(controller_t *controller)
{
    if (controller == NULL) {
        return;
    }

    controller->inlet_open = false;
    controller->heater_on = false;
    controller->state = CONTROLLER_STATE_SAFE_IDLE;
}

void controller_init(controller_t *controller)
{
    if (controller == NULL) {
        return;
    }

    controller_set_safe_idle(controller);
    controller->has_valid_temperature = false;
    controller->previous_temperature_c = 0;
    controller->last_temperature_c = 0;
    controller->last_temperature_ms = 0U;
    controller->has_valid_level = false;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
}

static bool controller_check_sensor_timeout(controller_t *controller, uint32_t now_ms)
{
    if (controller == NULL) {
        return false;
    }

    // Check temperature timeout
    if (controller->has_valid_temperature) {
        uint32_t temp_age_ms = now_ms - controller->last_temperature_ms;
        if (temp_age_ms > CONTROLLER_SENSOR_TIMEOUT_MS) {
            return true;
        }
    }

    // Check level timeout
    if (controller->has_valid_level) {
        uint32_t level_age_ms = now_ms - controller->last_level_ms;
        if (level_age_ms > CONTROLLER_SENSOR_TIMEOUT_MS) {
            return true;
        }
    }

    return false;
}

static void controller_apply_timeout(controller_t *controller)
{
    if (controller == NULL) {
        return;
    }

    // Reset sensor validity on timeout
    controller->has_valid_temperature = false;
    controller->has_valid_level = false;
    controller_set_safe_idle(controller);
}

static void controller_update_state_and_actuators(controller_t *controller, int level, int temperature_c)
{
    if (controller == NULL) {
        return;
    }

    bool was_inlet_open = controller->inlet_open;
    bool was_heater_on = controller->heater_on;

    // Start in safe idle state until both sensors are valid
    if (!controller->has_valid_temperature || !controller->has_valid_level) {
        controller_set_safe_idle(controller);
        return;
    }

    // Check for sensor timeout - forces safe all-off state
    if (controller_check_sensor_timeout(controller, 0)) {
        controller_apply_timeout(controller);
        return;
    }

    // Control policy implementation
    switch (true) {
        case (level < 60):
            // Low level: open inlet, heater off
            controller->inlet_open = true;
            controller->heater_on = false;
            controller->state = CONTROLLER_STATE_FILLING;
            break;

        case (level > 75):
            // High level: close inlet
            controller->inlet_open = false;
            controller->heater_on = false;
            if (controller->state == CONTROLLER_STATE_HEATING) {
                controller->state = CONTROLLER_STATE_HOLDING;
            }
            break;

        case (level < 55):
            // Level too low for heating: heater must be off
            controller->inlet_open = false;
            controller->heater_on = false;
            if (controller->state == CONTROLLER_STATE_HEATING) {
                controller->state = CONTROLLER_STATE_FILLING;
            }
            break;

        case (level >= 60 && level <= 75 && temperature_c < 45):
            // Safe level, low temp: close inlet, turn on heater
            controller->inlet_open = false;
            controller->heater_on = true;
            controller->state = CONTROLLER_STATE_HEATING;
            break;

        case (level >= 60 && level <= 75 && temperature_c >= 45 && temperature_c < 47):
            // Safe level, temp in lower band: close inlet, hold previous heater state
            controller->inlet_open = false;
            controller->heater_on = controller->heater_on;  // Hold previous
            if (controller->heater_on) {
                controller->state = CONTROLLER_STATE_HEATING;
            } else {
                controller->state = CONTROLLER_STATE_HOLDING;
            }
            break;

        case (level >= 60 && level <= 75 && temperature_c >= 47 && temperature_c <= 48):
            // Safe level, temp in upper band
            if (temperature_c > controller->previous_temperature_c) {
                // Temperature rising: turn heater off early
                controller->heater_on = false;
                controller->state = CONTROLLER_STATE_HOLDING;
            } else {
                // Temperature not rising: hold previous safe heater state
                controller->heater_on = controller->heater_on;  // Hold previous
                if (controller->heater_on) {
                    controller->state = CONTROLLER_STATE_HEATING;
                } else {
                    controller->state = CONTROLLER_STATE_HOLDING;
                }
            }
            break;

        case (level >= 60 && level <= 75 && temperature_c > 48):
            // Safe level, temp too high: close inlet, turn heater off
            controller->inlet_open = false;
            controller->heater_on = false;
            controller->state = CONTROLLER_STATE_HOLDING;
            break;

        default:
            // Default: maintain current state
            break;
    }

    // Update previous temperature for comparison in next step
    if (controller->has_valid_temperature) {
        controller->previous_temperature_c = controller->last_temperature_c;
    }
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .inlet_open = false,
        .heater_on = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };

    if (controller == NULL) {
        return output;
    }

    bool previous_inlet_open = controller->inlet_open;
    bool previous_heater_on = controller->heater_on;
    controller_state_t previous_state = controller->state;
    bool timed_out = false;

    // Handle sensor timeout first (takes precedence)
    if (input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT) {
        controller_apply_timeout(controller);
        output.timed_out = true;
        return output;
    }

    // Handle invalid inputs - force safe state
    if (input.kind == CONTROLLER_INPUT_INVALID_TEMPERATURE ||
        input.kind == CONTROLLER_INPUT_INVALID_LEVEL) {
        controller->has_valid_temperature = false;
        controller->has_valid_level = false;
        controller_set_safe_idle(controller);
        return output;
    }

    // Apply new sensor data
    switch (input.kind) {
    case CONTROLLER_INPUT_TEMPERATURE:
        controller->has_valid_temperature = true;
        controller->previous_temperature_c = controller->last_temperature_c;
        controller->last_temperature_c = input.temperature_c;
        controller->last_temperature_ms = input.now_ms;
        // Don't change state on temperature update alone if already in valid state
        break;

    case CONTROLLER_INPUT_LEVEL:
        controller->has_valid_level = true;
        controller->last_level = input.level;
        controller->last_level_ms = input.now_ms;
        // Don't change state on level update alone if already in valid state
        break;

    case CONTROLLER_INPUT_NONE:
    default:
        // No new input, but still need to check for timeout and apply control policy
        break;
    }

    // Check sensor timeout (applies even with CONTROLLER_INPUT_NONE)
    if (controller_check_sensor_timeout(controller, input.now_ms)) {
        controller_apply_timeout(controller);
        output.timed_out = true;
        return output;
    }

    // Only apply control policy when both sensors are valid
    if (controller->has_valid_temperature && controller->has_valid_level) {
        controller_update_state_and_actuators(controller, controller->last_level, controller->last_temperature_c);
    }

    // Build output
    output.inlet_open = controller->inlet_open;
    output.heater_on = controller->heater_on;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed =
        (previous_inlet_open != controller->inlet_open) ||
        (previous_heater_on != controller->heater_on) ||
        (previous_state != controller->state);

    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_FILLING:
        return "STATE FILLING";
    case CONTROLLER_STATE_HEATING:
        return "STATE HEATING";
    case CONTROLLER_STATE_HOLDING:
        return "STATE HOLDING";
    case CONTROLLER_STATE_SAFE_IDLE:
    default:
        return "STATE SAFE_IDLE";
    }
}
